import { AccountActions, CustomerActions } from '@semparar/mf-app-user';
import { NewVehiclesActions } from '@semparar/mf-app-vehicles';
import { additionalCardActions } from '../ducks/additionalCard';

import { AddressActions } from '../ducks/addressCard';
import { blockCardActions } from '../ducks/blockCard';
import { Creators as CashbackActions } from '../ducks/cashback';
import { ContentActions } from '../ducks/contents';
import { createPasswordActions } from '../ducks/createPassword';
import { credencialActions } from '../ducks/credencial';
import { cardsActions } from '../ducks/customers/cards';
import { productsAction } from '../ducks/customers/products';
import { automaticDebtActions } from '../ducks/dacc/automaticDebt';
import { partnerBanksActions } from '../ducks/dacc/partnerBanks';
import { duplicateCardActions } from '../ducks/duplicateCard';
import { homeInvoicesActions } from '../ducks/homeInvoices';
import { invoiceFintechActions } from '../ducks/invoice';
import { invoicesFintechActions } from '../ducks/invoices';
import { invoiceBarcodeActions } from '../ducks/invoices/barcode';
import { livenessActions } from '../ducks/liveness';
import { passwordActions } from '../ducks/password';
import { PointsActions } from '../ducks/points';
import { activitiesActions } from '../ducks/recentActivities';
import { simulationActions } from '../ducks/simulation';
import { unlockCardActions } from '../ducks/unlockCard';
import { updateLimitActions } from '../ducks/updateLimit';
import { virtualCardActions } from '../ducks/virtualCard';
import { DefaultActions } from './default';

export const FintechCardPlaceActions = {
  ...PointsActions,
  ...productsAction,
  ...invoiceFintechActions,
  ...invoicesFintechActions,
  ...CashbackActions,
  ...invoiceBarcodeActions,
  ...activitiesActions,
  ...automaticDebtActions,
  ...partnerBanksActions,
  ...virtualCardActions,
  ...cardsActions,
  ...livenessActions,
  ...credencialActions,
  ...createPasswordActions,
  ...unlockCardActions,
  ...blockCardActions,
  ...duplicateCardActions,
  ...passwordActions,
  ...simulationActions,
  ...AddressActions,
  ...ContentActions,
  ...additionalCardActions,
  ...updateLimitActions,
  ...homeInvoicesActions,
};

export const ActionCreators = {
  ...DefaultActions,
  ...CustomerActions,
  ...AccountActions,
  ...FintechCardPlaceActions,
  ...NewVehiclesActions,
};

