import { getMarketplace } from './marketplace/getMarketplace';
import { RescueTypes } from '../ducks/rescue';
import { postRescue } from './rescue';

export const FintechCardHomeSagas = [
  takeLatest(validateCardPasswordTypes.REQUEST, validateCardPasswordRequest),
  takeLatest(ProductsTypes.REQUEST, productsRequest),
  takeLatest(CashbackTypes.REQUEST_BALANCE, getBalanceCashback),
  takeLatest(CashbackTypes.REQUEST_EXTRACT, getExtractCashback),
  takeLeading(CashbackTypes.REQUEST_REDEEM, getRedeemCashback),
  takeLatest(CashbackTypes.REQUEST_CASH_TRANSACTIONS, getCashbackTransactions),
  takeLatest(PointsTypes.REQUEST_BALANCE, getPointsBalance),
  takeLatest(PointsTypes.REQUEST_PRODUCTS, getPointsProducts),
  takeLatest(PointsTypes.REQUEST_PARAMETERIZATION, getParameterization),
  takeLatest(InvoiceBarcodeTypes.REQUEST, getInvoicesBarcode),
  takeLatest(InvoiceTypes.REQUEST_FINTECH_INVOICE, getInvoice),
  takeLatest(InvoiceTypes.REQUEST_FINTECH_INVOICE_DETAILS, getInvoiceDetails),
  takeLatest(DownloadInvoiceTypes.REQUEST, downloadInvoiceRequest),
  takeLatest(InvoicesTypes.REQUEST_FINTECH_INVOICES, getInvoices),
  takeLatest(HomeInvoicesTypes.REQUEST_HOME_INVOICES, getHomeInvoices),
  takeLatest(InvoicesListTypes.REQUEST_FINTECH_INVOICES_LIST, listAllInvoices),
  takeLatest(InvoicesListTypes.REQUEST_FINTECH_INVOICE_PDF, getInvoicePDF),
  takeLatest(PartnerBanksTypes.PARTNER_BANKS_REQUEST, getSPMaisPartnerBanks),
  takeLatest(PaymentChangeTypes.PAYMENT_CHANGE_REQUEST, saveNewPaymentOption),
  takeLatest(AutomaticDebitTypes.AUTOMATIC_DEBIT_REQUEST, getAutoDebtSituation),
  takeLatest(ActivitiesTypes.REQUEST_ACTIVITIES, getActivitiesRequest),
  takeLatest(VirtualCardTypes.GET_VIRTUAL_CARD, putVirtualCard),
  takeLatest(CardsTypes.REQUEST, getCustomersCards),
  takeLatest(LivenessTypes.REQUEST, postLiveness),
  takeLatest(CredencialTypes.REQUEST, credencialRequest),
  takeLatest(CreatePasswordTypes.REQUEST, createPasswordRequest),
  takeLatest(UnlockCardTypes.REQUEST, unlockCardRequest),
  takeLatest(BlockCardTypes.REQUEST, blockCardRequest),
  takeLatest(DuplicateCardTypes.REQUEST, duplicateCardRequest),
  takeLatest(VirtualCardTypes.GET_VIRTUAL_CARD_CVV, getVirtualCardCVV),
  takeLatest(PasswordTypes.REQUEST, getPassword),
  takeLatest(SimulationTypes.REQUEST, getSimulationRequest),
  takeLatest(WithdrawTypes.GET_WITHDRAW, getWithdraw),
  takeLatest(WithdrawTypes.UNLOCK_WITHDRAW, unlockWithdraw),
  takeLatest(addressTypes.POST_REQUEST, editAddress),
  takeLatest(ContentTypes.REQUEST, getDynamicContent),
  takeLatest(AdditionalCardTypes.REQUEST_NAME, additionalCardRequestName),
  takeLatest(
    AdditionalCardTypes.REQUEST_ADDITIONAL_CARD,
    additionalCardRequest,
  ),
  takeLatest(UpdateLimitTypes.UPDATE_LIMIT_REQUEST, updateLimitRequest),
  takeLatest(
    ExemptionEligibilityTypes.REQUEST_EXEMPTION_ELIGIBILITY,
    getExemptionEligibility,
  ),
  takeLatest(CardTrackingTypes.REQUEST_CARD_TRACKING, cardTrackingRequest),
  takeLatest(PointsTypes.REQUEST_BALANCE, getPointsBalance),
  takeLatest(PointsTypes.REQUEST_PRODUCTS, getPointsProducts),
  takeLatest(PointsTypes.REQUEST_EXTRACT, getPointsExtract),
  takeLatest(PointsTypes.REQUEST_INITIAL_DATA, getInitialPointsData),
  takeLatest(GetMarketplacTypes.REQUEST_GET_MARKETPLACE, getMarketplace),
  takeLatest(GetMarketplacTypes.REQUEST_GET_MARKETPLACE, getMarketplace),
  takeLeading(RescueTypes.REQUEST, postRescue),
];

export default function* rootSaga() {
  return yield all([
    takeLatest(SearchCepTypes.REQUEST, searchCepRequest),
    takeLatest(ExampleTypes.REQUEST, exampleRequest),
    takeLatest(CustomerActionsTypes.GET_DATA, getData),
    takeLatest(CustomerActionsTypes.REQUEST_RESUMED, resumed),
    takeLatest(CustomerActionsTypes.REQUEST_DEVICE_VERIFY, verifyDevice),
    takeLatest(CustomerActionsTypes.LOGOUT, logout),
    takeLatest(CustomerActionsTypes.REQUEST_DEVICE_INFO, requestDeviceInfo),
    takeLatest(CustomerActionsTypes.CHANGE_VISIBLE_CAROUSEL, changeVisibleCarousel),
    takeLatest(CustomerActionsTypes.AUTH, auth),
    // takeLatest(CustomerActionsTypes.AUTH_CREDIT_CARD, authCreditCard),
    takeLatest(CustomerActionsTypes.REFRESH, refresh),
    takeLatest(CustomerActionsTypes.REFRESH_TOKEN, refreshToken),
    takeLatest(CustomerActionsTypes.SAVE_TOKEN, saveToken),
    takeLatest(AccountActionsTypes.GET_DATA, getDataAccount),
    takeLatest(AccountActionsTypes.UPDATE_DATA, updateAccount),
    takeLatest(AccountActionsTypes.REQUEST_OPEN_BALANCE, getOpenItems),
    takeLatest(CustomerActionsTypes.CHECK_CLIENT_TYPE, checkClientType),
    takeLatest(CustomerActionsTypes.REQUEST_CUSTOMER_DATA, getCustomerData),
    takeLatest(CustomerActionsTypes.UPDATE_CUSTOMER_DATA, updateCustomerData),
    takeLatest(CustomerActionsTypes.GET_PRODUCTS, getProducts),
    takeLatest(UpdatePersonalPasswordTypes.GET, updatePassword),
    takeLatest(NewVehiclesTypes.GET_VEHICLES_REQUEST, getVehicles),

    ...FintechCardHomeSagas,
  ]);
}

