     2→import createReducer from '~/redux/store/createReducer';
     3→
     4→import { CustomTransactionsData } from '../../atomic/organisms/CashbackCellDropdown/Models';
     5→
     6→export const Types = {
     7→
     8→  SUCCESS_BALANCE: '@cashback/SUCCESS_BALANCE',
     9→  FAILED_BALANCE: '@cashback/FAILED_BALANCE',
    10→  REQUEST_BALANCE: '@cashback/REQUEST_BALANCE',
    11→
    12→  REQUEST_EXTRACT: '@cashback/REQUEST_EXTRACT',
    13→  SUCCESS_EXTRACT: '@cashback/SUCCESS_EXTRACT',
    14→  FAILED_EXTRACT: '@cashback/FAILED_EXTRACT',
    15→
    16→  REQUEST_REDEEM: '@cashback/REQUEST_REDEEM',
    17→  SUCCESS_REDEEM: '@cashback/SUCCESS_REDEEM',
    18→  FAILED_REDEEM: '@cashback/FAILED_REDEEM',
    19→  CLEAN_LOADING_REDEEM: '@cashback/CLEAN_LOADING_REDEEM',
    20→  SET_HAS_REDEEMED_BEFORE: '@cashback/SET_HAS_REDEEMED_BEFORE',
    21→
    22→  REQUEST_CASH_TRANSACTIONS: '@cashback/REQUEST_CASH_TRANSACTIONS',
    23→  SUCCESS_CASH_TRANSACTIONS: '@cashback/SUCCESS_CASH_TRANSACTIONS',
    24→  FAILED_CASH_TRANSACTIONS: '@cashback/FAILED_CASH_TRANSACTIONS',
    25→  CLEAN_CASH_TRANSACTIONS: '@cashback/CLEAN_CASH_TRANSACTIONS',
    26→
    27→  CLEAR_STATES: '@cashback/CLEAR_STATES',
    28→  CLEAR: '@cashback/CLEAR',
    29→};
    30→
    31→export type CashbackStatus = 'CREDITO' | 'DEBITO' | 'VENCIDO';
    32→
    33→export type CashbackRedeemCallback = (data: {
    34→  statusCode: number | undefined;
    35→}) => void;
    36→
    37→export interface CashbackData {
    38→  data: string;
    39→  descricao: string;
    40→  dtExpiracao: string;
    41→  valor: number;
    42→  status: CashbackStatus;
    43→}
    44→
    45→export interface Transactions {
    46→  name: string;
    47→  basePrice: number;
    48→  value: number;
    49→  percentage: number;
    50→  date: Date;
    51→}
    52→
    53→export interface TransactionData {
    54→  pendingBalance: number;
    55→  transactions: CustomTransactionsData[];
    56→  transactionPending: CustomTransactionsData[];
    57→}
    58→
    59→export interface InitialState {
    60→
    61→  balance: number | undefined;
    62→  isLoadingBalance: boolean;
    63→  isErrorBalance: boolean;
    64→
    65→  data: CashbackData[];
    66→  dataGroupedByDay: PropsItemsTransactionsList[];
    67→  isLoadingExtract: boolean;
    68→  isErrorExtract: boolean;
    69→
    70→  isLoadingRedeem: boolean;
    71→  isErrorRedeem: boolean;
    72→  hasRedeemedBefore: boolean;
    73→
    74→  transactions: TransactionData;
    75→  isLoadingTransactions: boolean;
    76→  isErrorTransactions: boolean;
    77→}
    78→
    79→export type State = InitialState;
    80→
    81→const initialTransactions: TransactionData = {
    82→  pendingBalance: 0,
    83→  transactions: [],
    84→  transactionPending: [],
    85→};
    86→
    87→export const initialState: InitialState = {
    88→  isLoadingBalance: true,
    89→  isErrorBalance: false,
    90→  balance: undefined,
    91→  isLoadingExtract: false,
    92→  isErrorExtract: false,
    93→  data: [],
    94→  dataGroupedByDay: [],
    95→  isErrorRedeem: false,
    96→  isLoadingRedeem: false,
    97→  hasRedeemedBefore: false,
    98→  transactions: initialTransactions,
    99→  isErrorTransactions: false,
   100→  isLoadingTransactions: false,
   101→};
   102→
   103→export const fintechCashbackReducer = createReducer(initialState, {
   104→  [Types.REQUEST_BALANCE](state: State): State {
   105→    return {
   106→      ...state,
   107→      isLoadingBalance: true,
   108→      isErrorBalance: false,
   109→    };
   110→  },
   111→  [Types.SUCCESS_BALANCE](
   112→    state: State,
   113→    { balance }: { balance: State['balance'] },
   114→  ) {
   115→    return {
   116→      ...state,
   117→      balance,
   118→      isLoadingBalance: false,
   119→      isError: false,
   120→    };
   121→  },
   122→  [Types.FAILED_BALANCE](state: State): State {
   123→    return {
   124→      ...state,
   125→      isLoadingBalance: false,
   126→      isErrorBalance: true,
   127→    };
   128→  },
   129→  [Types.REQUEST_EXTRACT](state: State): State {
   130→    return {
   131→      ...state,
   132→      data: initialState.data,
   133→      isErrorExtract: false,
   134→      isLoadingExtract: true,
   135→    };
   136→  },
   137→  [Types.SUCCESS_EXTRACT](
   138→    state: State,
   139→    {
   140→      data: { data, dataGroupedByDay },
   141→    }: {
   142→      data: {
   143→        data: State['data'];
   144→        dataGroupedByDay: State['dataGroupedByDay'];
   145→      };
   146→    },
   147→  ) {
   148→    return {
   149→      ...state,
   150→      data,
   151→      dataGroupedByDay,
   152→      isLoadingExtract: false,
   153→      isErrorExtract: false,
   154→    };
   155→  },
   156→  [Types.REQUEST_REDEEM](state: State): State {
   157→    return {
   158→      ...state,
   159→      isLoadingRedeem: true,
   160→      isErrorRedeem: false,
   161→    };
   162→  },
   163→  [Types.SUCCESS_REDEEM](state: State): State {
   164→    return {
   165→      ...state,
   166→      isLoadingRedeem: false,
   167→      isErrorRedeem: false,
   168→    };
   169→  },
   170→  [Types.SET_HAS_REDEEMED_BEFORE](state: State): State {
   171→    return {
   172→      ...state,
   173→      hasRedeemedBefore: true,
   174→    };
   175→  },
   176→  [Types.FAILED_REDEEM](state: State): State {
   177→    return {
   178→      ...state,
   179→      isLoadingRedeem: false,
   180→      isErrorRedeem: true,
   181→    };
   182→  },
   183→  [Types.FAILED_EXTRACT](state: State): State {
   184→    return {
   185→      ...state,
   186→      isLoadingExtract: false,
   187→      isErrorExtract: true,
   188→    };
   189→  },
   190→  [Types.CLEAR_STATES](state: State): State {
   191→    return {
   192→      ...state,
   193→      isErrorBalance: false,
   194→      isErrorRedeem: false,
   195→      isErrorExtract: false,
   196→      isLoadingBalance: false,
   197→      isLoadingExtract: false,
   198→      isLoadingRedeem: false,
   199→    };
   200→  },
   201→  [Types.CLEAN_LOADING_REDEEM](state: State): State {
   202→    return {
   203→      ...state,
   204→      isLoadingRedeem: false,
   205→    };
   206→  },
   207→  [Types.CLEAR](): State {
   208→    return initialState;
   209→  },
   210→  [Types.REQUEST_CASH_TRANSACTIONS](state: State): State {
   211→    return {
   212→      ...state,
   213→      isLoadingTransactions: true,
   214→      isErrorTransactions: false,
   215→    };
   216→  },
   217→  [Types.SUCCESS_CASH_TRANSACTIONS](state: State, { transactions }): State {
   218→    return {
   219→      ...state,
   220→      transactions,
   221→      isLoadingTransactions: false,
   222→    };
   223→  },
   224→  [Types.FAILED_CASH_TRANSACTIONS](state: State): State {
   225→    return {
   226→      ...state,
   227→      isErrorTransactions: true,
   228→      isLoadingTransactions: false,
   229→    };
   230→  },
   231→  [Types.CLEAN_CASH_TRANSACTIONS](state: State): State {
   232→    return {
   233→      ...state,
   234→      transactions: initialTransactions,
   235→      isErrorTransactions: false,
   236→      isLoadingTransactions: false,
   237→    };
   238→  },
   239→});
   240→
   241→export const Creators = {
   242→  requestBalance: () => ({
   243→    type: Types.REQUEST_BALANCE,
   244→  }),
   245→  successBalance: (balance: State['balance']) => ({
   246→    type: Types.SUCCESS_BALANCE,
   247→    balance,
   248→  }),
   249→  failedBalance: () => ({
   250→    type: Types.FAILED_BALANCE,
   251→  }),
   252→  failedExtract: () => ({
   253→    type: Types.FAILED_EXTRACT,
   254→  }),
   255→  requestExtract: () => ({
   256→    type: Types.REQUEST_EXTRACT,
   257→  }),
   258→  successExtract: (data: {
   259→    data: State['data'];
   260→    dataGroupedByDay: State['dataGroupedByDay'];
   261→  }) => ({
   262→    type: Types.SUCCESS_EXTRACT,
   263→    data,
   264→  }),
   265→  requestRedeem: (value: number, callback: CashbackRedeemCallback) => ({
   266→    type: Types.REQUEST_REDEEM,
   267→    value,
   268→    callback,
   269→  }),
   270→  successRedeem: () => ({
   271→    type: Types.SUCCESS_REDEEM,
   272→  }),
   273→  failedRedeem: () => ({
   274→    type: Types.FAILED_REDEEM,
   275→  }),
   276→  setHasRedeemedBefore: () => ({
   277→    type: Types.SET_HAS_REDEEMED_BEFORE,
   278→  }),
   279→  clearStates: () => ({
   280→    type: Types.CLEAR_STATES,
   281→  }),
   282→  clear: () => ({
   283→    type: Types.CLEAR,
   284→  }),
   285→  requestCashTransactions: () => ({
   286→    type: Types.REQUEST_CASH_TRANSACTIONS,
   287→  }),
   288→  succesCashTransactions: (transactions: TransactionData) => ({
   289→    type: Types.SUCCESS_CASH_TRANSACTIONS,
   290→    transactions,
   291→  }),
   292→  failedCashTransactions: () => ({
   293→    type: Types.FAILED_CASH_TRANSACTIONS,
   294→  }),
   295→  cleanCashTransactions: () => ({
   296→    type: Types.CLEAN_CASH_TRANSACTIONS,
   297→  }),
   298→  clearRedeemLoading: () => ({
   299→    type: Types.CLEAN_LOADING_REDEEM,
   300→  }),
   301→};
   302→
   303→export default fintechCashbackReducer;
   304→

