  REQUEST_CASH_TRANSACTIONS: '@cashback/REQUEST_CASH_TRANSACTIONS',
  SUCCESS_CASH_TRANSACTIONS: '@cashback/SUCCESS_CASH_TRANSACTIONS',
  FAILED_CASH_TRANSACTIONS: '@cashback/FAILED_CASH_TRANSACTIONS',
  CLEAN_CASH_TRANSACTIONS: '@cashback/CLEAN_CASH_TRANSACTIONS',

  CLEAR_STATES: '@cashback/CLEAR_STATES',
  CLEAR: '@cashback/CLEAR',
};

export type CashbackStatus = 'CREDITO' | 'DEBITO' | 'VENCIDO';

export type CashbackRedeemCallback = (data: {
  statusCode: number | undefined;
}) => void;

export interface CashbackData {
  data: string;
  descricao: string;
  dtExpiracao: string;
  valor: number;
  status: CashbackStatus;
}

export interface Transactions {
  name: string;
  basePrice: number;
  value: number;
  percentage: number;
  date: Date;
}

export interface TransactionData {
  pendingBalance: number;
  transactions: CustomTransactionsData[];
  transactionPending: CustomTransactionsData[];
}

export interface InitialState {

  balance: number | undefined;
  isLoadingBalance: boolean;
  isErrorBalance: boolean;

  data: CashbackData[];
  dataGroupedByDay: PropsItemsTransactionsList[];
  isLoadingExtract: boolean;
  isErrorExtract: boolean;

  isLoadingRedeem: boolean;
  isErrorRedeem: boolean;
  hasRedeemedBefore: boolean;

  transactions: TransactionData;
  isLoadingTransactions: boolean;
  isErrorTransactions: boolean;
}

export type State = InitialState;

const initialTransactions: TransactionData = {
  pendingBalance: 0,
  transactions: [],
  transactionPending: [],
};

export const initialState: InitialState = {
  isLoadingBalance: true,
  isErrorBalance: false,
  balance: undefined,
  isLoadingExtract: false,
  isErrorExtract: false,
  data: [],
  dataGroupedByDay: [],
  isErrorRedeem: false,
  isLoadingRedeem: false,
  hasRedeemedBefore: false,
  transactions: initialTransactions,
  isErrorTransactions: false,
  isLoadingTransactions: false,
};

export const fintechCashbackReducer = createReducer(initialState, {
  [Types.REQUEST_BALANCE](state: State): State {
    return {
      ...state,
      isLoadingBalance: true,
      isErrorBalance: false,
    };
  },
  [Types.SUCCESS_BALANCE](
    state: State,
    { balance }: { balance: State['balance'] },
  ) {
    return {
      ...state,
      balance,
      isLoadingBalance: false,
      isError: false,
    };
  },
  [Types.FAILED_BALANCE](state: State): State {
    return {
      ...state,
      isLoadingBalance: false,
      isErrorBalance: true,
    };
  },
  [Types.REQUEST_EXTRACT](state: State): State {
    return {
      ...state,
      data: initialState.data,
      isErrorExtract: false,
      isLoadingExtract: true,
    };
  },
  [Types.SUCCESS_EXTRACT](
    state: State,
    {
      data: { data, dataGroupedByDay },
    }: {
      data: {
        data: State['data'];
        dataGroupedByDay: State['dataGroupedByDay'];
      };
    },
  ) {
    return {
      ...state,
      data,
      dataGroupedByDay,
      isLoadingExtract: false,
      isErrorExtract: false,
    };
  },
  [Types.REQUEST_REDEEM](state: State): State {
    return {
      ...state,
      isLoadingRedeem: true,
      isErrorRedeem: false,
    };
  },
  [Types.SUCCESS_REDEEM](state: State): State {
    return {
      ...state,
      isLoadingRedeem: false,
      isErrorRedeem: false,
    };
  },
  [Types.SET_HAS_REDEEMED_BEFORE](state: State): State {
    return {
      ...state,
      hasRedeemedBefore: true,
    };
  },
  [Types.FAILED_REDEEM](state: State): State {
    return {
      ...state,
      isLoadingRedeem: false,
      isErrorRedeem: true,
    };
  },
  [Types.FAILED_EXTRACT](state: State): State {
    return {
      ...state,
      isLoadingExtract: false,
      isErrorExtract: true,
    };
  },
  [Types.CLEAR_STATES](state: State): State {
    return {
      ...state,
      isErrorBalance: false,
      isErrorRedeem: false,
      isErrorExtract: false,
      isLoadingBalance: false,
      isLoadingExtract: false,
      isLoadingRedeem: false,
    };
  },
  [Types.CLEAN_LOADING_REDEEM](state: State): State {
    return {
      ...state,
      isLoadingRedeem: false,
    };
  },
  [Types.CLEAR](): State {
    return initialState;
  },
  [Types.REQUEST_CASH_TRANSACTIONS](state: State): State {
    return {
      ...state,
      isLoadingTransactions: true,
      isErrorTransactions: false,
    };
  },
  [Types.SUCCESS_CASH_TRANSACTIONS](state: State, { transactions }): State {
    return {
      ...state,
      transactions,
      isLoadingTransactions: false,
    };
  },
  [Types.FAILED_CASH_TRANSACTIONS](state: State): State {
    return {
      ...state,
      isErrorTransactions: true,
      isLoadingTransactions: false,
    };
  },
  [Types.CLEAN_CASH_TRANSACTIONS](state: State): State {
    return {
      ...state,
      transactions: initialTransactions,
      isErrorTransactions: false,
      isLoadingTransactions: false,
    };
  },
});

export const Creators = {
  requestBalance: () => ({
    type: Types.REQUEST_BALANCE,
  }),
  successBalance: (balance: State['balance']) => ({
    type: Types.SUCCESS_BALANCE,
    balance,
  }),
  failedBalance: () => ({
    type: Types.FAILED_BALANCE,
  }),
  failedExtract: () => ({
    type: Types.FAILED_EXTRACT,
  }),
  requestExtract: () => ({
    type: Types.REQUEST_EXTRACT,
  }),
  successExtract: (data: {
    data: State['data'];
    dataGroupedByDay: State['dataGroupedByDay'];
  }) => ({
    type: Types.SUCCESS_EXTRACT,
    data,
  }),
  requestRedeem: (value: number, callback: CashbackRedeemCallback) => ({
    type: Types.REQUEST_REDEEM,
    value,
    callback,
  }),
  successRedeem: () => ({
    type: Types.SUCCESS_REDEEM,
  }),
  failedRedeem: () => ({
    type: Types.FAILED_REDEEM,
  }),
  setHasRedeemedBefore: () => ({
    type: Types.SET_HAS_REDEEMED_BEFORE,
  }),
  clearStates: () => ({
    type: Types.CLEAR_STATES,
  }),
  clear: () => ({
    type: Types.CLEAR,
  }),
  requestCashTransactions: () => ({
    type: Types.REQUEST_CASH_TRANSACTIONS,
  }),
  succesCashTransactions: (transactions: TransactionData) => ({
    type: Types.SUCCESS_CASH_TRANSACTIONS,
    transactions,
  }),
  failedCashTransactions: () => ({
    type: Types.FAILED_CASH_TRANSACTIONS,
  }),
  cleanCashTransactions: () => ({
    type: Types.CLEAN_CASH_TRANSACTIONS,
  }),
  clearRedeemLoading: () => ({
    type: Types.CLEAN_LOADING_REDEEM,
  }),
};

export default fintechCashbackReducer;

