import {
  PropsItemsTransactions,
  PropsItemsTransactionsList,
} from '@semparar/design-system-app/src/atomic/fintech/TransactionsList/Models';
import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export const ActivitiesTypes = {
  REQUEST_ACTIVITIES: '@activities/requestActivities',
  SUCCESS_ACTIVITIES: '@activities/successActivities',
  FAILED: '@activities/failed',
  CLEAR: '@activities/clear',
};

export type ActiveType = 'C' | 'D';

export interface ActivitiesResponseData {
  code: number;
  message: string;
  data: ActivityData[];
}
export interface ActivityData {
  Tipo: ActiveType;
  Data: string;
  Hora: string;
  CodigoEstabelecimento: string;
  NomeEstabelecimento: string;
  MoedaOrigem: string;
  ValorMoedaOrigem: number;
  MoedaFaturamento: string;
  FormaCaptura: string;
  NumeroParcelas: number;
  ValorParcela: number;
  Descricao: string;
  NumeroCartao: string;
  TipoParcelamento: string;
  CodigoPais: string;
}

export type ActivitiesListVariants = Record<ActiveType, PropsItemsTransactions>;

export interface ActivitiesReducerProps {
  isLoading: true;
  isError: false;
  dataGroupedByDay: PropsItemsTransactionsList[] | undefined;
  data: undefined | ActivitiesResponseData['data'];
}

export type State = ActivitiesReducerProps;

export const initialState: ActivitiesReducerProps = {
  isLoading: true,
  isError: false,
  dataGroupedByDay: undefined,
  data: undefined,
};

export const activitiesReducer = createReducer(initialState, {
  [ActivitiesTypes.REQUEST_ACTIVITIES](state: State) {
    return {
      ...state,
      isLoading: true,
      isError: false,
    };
  },
  [ActivitiesTypes.SUCCESS_ACTIVITIES](
    state: State,
    {
      data: { data, dataGroupedByDay },
    }: {
      data: {
        data: State['data'];
        dataGroupedByDay: State['dataGroupedByDay'];
      };
    },
  ) {
    return {
      ...state,
      data,
      dataGroupedByDay,
      isLoading: false,
      isError: false,
    };
  },
  [ActivitiesTypes.FAILED]() {
    return {
      ...initialState,
      isLoadingOffers: false,
      isLoading: false,
      isError: true,
    };
  },
});

export interface ActivitiesActions {
  requestActivities: () => Action;
  successActivities: (data: {
    data: ActivitiesResponseData['data'];
    dataGroupedByDay: State['dataGroupedByDay'];
  }) => Action;

  failed: () => Action;
  clear: () => Action;
}

export const activitiesActions: ActivitiesActions = {
  requestActivities: () => ({
    type: ActivitiesTypes.REQUEST_ACTIVITIES,
  }),
  successActivities: (data: {
    data: ActivitiesResponseData['data'];
    dataGroupedByDay: State['dataGroupedByDay'];
  }) => ({
    type: ActivitiesTypes.SUCCESS_ACTIVITIES,
    data,
  }),
  failed: () => ({
    type: ActivitiesTypes.FAILED,
  }),
  clear: () => ({
    type: ActivitiesTypes.CLEAR,
  }),
};

export default activitiesReducer;

