import { PropsItems as ExtractTabPropsItems } from '@semparar/design-system-app/src/atomic/fintech/ExtractTab/Models';
import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export type InvoiceStatusTypes =
  | 'open'
  | 'paid'
  | 'default'
  | 'delayed'
  | 'closed'
  | 'late'
  | 'paidMessage'
  | 'unidentifiedPayment'
  | 'debitPayment';

export enum InvoicesTypes {
  REQUEST_FINTECH_INVOICES = '@invoices/REQUEST_FINTECH_INVOICES',
  SUCCESS_FINTECH_INVOICES = '@invoices/SUCCESS_FINTECH_INVOICES',
  FAILED_FINTECH_INVOICES = '@invoices/FAILED_FINTECH_INVOICES',
  CLEAN = '@invoices/CLEAN',
}

export type Situation = 'closed' | 'Fechada' | 'Em Aberto';

export type Payment = 'Pago Integral' | 'Não Pago' | 'Pago Parcial';

export interface InvoicesFintechResponse {
  data: {
    invoices: InvoiceFintechItem[];
  };
}

export interface InvoiceFintechItem {
  Fechamento: string;
  Vencimento: string;
  Valor: number;
  ValorPago: number;
  Situacao: Situation | InvoiceStatusTypes;
  Pagamento: Payment;
  ValorPgtoMinimo: number;
  VencimentoOriginal: string;
  MelhorDiaCompra?: string;
  DataDeCorte?: string;
  ParcelamentoDisponivel?: boolean;
}
export interface InvoicesFintechProps {
  isLoading: boolean;
  isError: boolean;
  data: InvoiceFintechItem[];
  invoiceMonths: (ExtractTabPropsItems & { situation: Situation })[];
}

export type State = InvoicesFintechProps;

export const initialState: InvoicesFintechProps = {
  isLoading: false,
  isError: false,
  data: [],
  invoiceMonths: [],
};

export const invoicesFintechReducer = createReducer(initialState, {
  [InvoicesTypes.REQUEST_FINTECH_INVOICES](state: State): State {
    return {
      ...state,
      isLoading: true,
      isError: false,
    };
  },
  [InvoicesTypes.SUCCESS_FINTECH_INVOICES](
    state: State,
    {
      data: { response, invoiceMonths },
    }: {
      data: {
        response: InvoicesFintechProps['data'];
        invoiceMonths: (ExtractTabPropsItems & { situation: Situation })[];
      };
    },
  ): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      data: response,
      invoiceMonths,
    };
  },
  [InvoicesTypes.FAILED_FINTECH_INVOICES](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [InvoicesTypes.CLEAN](): State {
    return initialState;
  },
});

