import { AdditionalCardSlice, createAdditionalCardSlice } from "../../services/additionalCard/store";
import { AirlineMilesSlice, createAirlineMilesSlice } from "./rewardProgram/store";
import { StateCreator } from "zustand";
import { createParameterPointsProgramSlice, ParameterPointsProgramSlice } from "./rewardProgram/store";

export type CardPlaceRootStore = ParameterPointsProgramSlice & AdditionalCardSlice & AirlineMilesSlice;
export type Slice<T> = StateCreator<CardPlaceRootStore, [], [], T>;
export const asSlice = <T>(slice: StateCreator<CardPlaceRootStore, [], [], T>) => slice as Slice<T>;

export function setSlicesCardPlace<T extends CardPlaceRootStore>(...a: Parameters<Slice<T>>) {
  return {
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(...a),
    ...asSlice<AdditionalCardSlice>(createAdditionalCardSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
  }
}

import type { StateCreator } from 'zustand';
import type { AirlineMilesActions, AirlineMilesState } from '../models';

export type AirlineMilesSlice = {
  airlineMiles: AirlineMilesState;
  airlineMilesActions: AirlineMilesActions;
};

const initialAirlineMilesState: AirlineMilesState = {
  redirectURL: '',
  isLoading: false,
  isError: false,
  errorMessage: '',
};

export const createAirlineMilesSlice: StateCreator<
  AirlineMilesSlice,
  [],
  [],
  AirlineMilesSlice
> = (set) => ({
  airlineMiles: initialAirlineMilesState,

  airlineMilesActions: {
    setRedirectURL: (url) =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          redirectURL: url,
          isLoading: false,
          isError: false,
          errorMessage: '',
        },
      })),

    setLoading: (isLoading) =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          isLoading,
          ...(isLoading && {
            isError: false,
            errorMessage: '',
          }),
        },
      })),

    setError: (error) =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          isLoading: false,
          isError: true,
          errorMessage: error,
        },
      })),

    clearError: () =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          isError: false,
          errorMessage: '',
        },
      })),

    reset: () =>
      set({
        airlineMiles: initialAirlineMilesState,
      }),
  },
});

