import AsyncStorage from '@react-native-async-storage/async-storage';
import CryptoES from 'crypto-es';
import { Storage } from 'redux-persist';

const STORAGE_KEY = 'persist:root';

const sqliteStorage = AsyncStorage;

const getEncrypted = async (value: string) => {
  const uuid = "await getUUID()";
  const secretKey = CryptoES.SHA256(STORAGE_KEY + uuid).toString();
  const key = CryptoES.enc.Hex.parse(secretKey.substring(0, 32));
  const iv = CryptoES.enc.Hex.parse(secretKey.substring(32, 48));
  const encrypted = CryptoES.AES.encrypt(value, key, {
    iv,
    mode: CryptoES.mode.CBC,
    padding: CryptoES.pad.Pkcs7,
  });
  const encrypt = encrypted.toString();
  return encrypt;
};

const getDecrypted = async (value: string) => {
  const uuid = "await getUUID()";
  const secretKey = CryptoES.SHA256(STORAGE_KEY + uuid).toString();
  const key = CryptoES.enc.Hex.parse(secretKey.substring(0, 32));
  const iv = CryptoES.enc.Hex.parse(secretKey.substring(32, 48));
  const decrypted = CryptoES.AES.decrypt(value, key, {
    iv,
    mode: CryptoES.mode.CBC,
    padding: CryptoES.pad.Pkcs7,
  });
  return decrypted.toString(CryptoES.enc.Utf8);
};

const storage: Storage = {
  async setItem(key, value) {
    return sqliteStorage.setItem(STORAGE_KEY + key, await getEncrypted(value));
  },
  async getItem(key) {
    const data = await sqliteStorage.getItem(STORAGE_KEY + key);
    if (!data) return Promise.resolve(data);
    return Promise.resolve(await getDecrypted(data));
  },
  async removeItem(key) {
    await sqliteStorage.removeItem(STORAGE_KEY + key);
    return Promise.resolve();
  },
};

export default storage;

